// Extract prompt safely
let prompt = $json.body?.prompt || "";

// Normalize formatting
prompt = prompt
  .replace(/\r\n/g, "\n")        // normalize Windows line breaks
  .replace(/\n\s+\n/g, "\n\n")   // remove excessive spacing
  .trim();                       // remove leading/trailing spaces

return [
  {
    json: {
      prompt: prompt
    }
  }
];

// Step 1: Get the raw output string
let rawOutput = $json.output;

// Step 2: Ensure it's a string
if (typeof rawOutput !== "string") {
  throw new Error("Output is not a string");
}

// Step 3: Parse JSON safely
let parsedWorkflow;

try {
  parsedWorkflow = JSON.parse(rawOutput);
} catch (error) {
  throw new Error("Invalid JSON returned by AI: " + error.message);
}

// Step 4: Return clean normalized JSON
return [
  {
    json: parsedWorkflow
  }
];
